#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007
#define MAXN 200000
#define MAXM 1000000000000000000
long long powmod(long long a, long long b, long long mod) {
    long long res = 1;
    while (b > 0) {
        if (b & 1) res = (res * a) % mod;
        a = (a * a) % mod;
        b >>= 1;
    }
    return res;
}
long long inv(long long a, long long mod) {
    return powmod(a, mod - 2, mod);
}
int main() {
    long long n, m;
    scanf("%lld %lld", &n, &m);
    long long *dp = (long long *)malloc((m + 1) * sizeof(long long));
    dp[0] = 0;
    for (long long i = 1; i <= m; i++) {
        dp[i] = 1;
        for (long long r = 1; r <= n; r++) {
            long long new_m = i % r;
            dp[i] = (dp[i] + dp[new_m]) % MOD;
        }
        dp[i] = (dp[i] * inv(n, MOD)) % MOD;
    }
    printf("%lld\n", dp[m]);
    free(dp);
    return 0;
}

