public class Main {
    static final long MOD = 1000000007;
    static final long MAXN = 200000;
    static final long MAXM = 1000000000000000000L;
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        long n = Long.parseLong(st.nextToken());
        long m = Long.parseLong(st.nextToken());
        long[] dp = new long[(int) (m + 1)];
        dp[0] = 0;
        for (long i = 1; i <= m; i++) {
            dp[(int) i] = 1;
            for (long r = 1; r <= n; r++) {
                long new_m = i % r;
                dp[(int) i] = (dp[(int) i] + dp[(int) new_m]) % MOD;
            }
            dp[(int) i] = (dp[(int) i] * inv(n, MOD)) % MOD;
        }
        System.out.println(dp[(int) m]);
    }
    static long powmod(long a, long b, long mod) {
        long res = 1;
        while (b > 0) {
            if (b % 2 == 1) res = (res * a) % mod;
            a = (a * a) % mod;
            b >>= 1;
        }
        return res;
    }
    static long inv(long a, long mod) {
        return powmod(a, mod - 2, mod);
    }
